import Image from 'next/image';
import Navbar from '@/app/ui/dashboard/Navbar';
import axios from 'axios';
import ProductCard from '@/app/ui/dashboard/ProductCard';

export default async function Gallery() {

    // 拿取商品資料
    const baseUrl = process.env.NEXT_PUBLIC_API_BASE_URL;

    let products = [];
    try {
        const res = await fetch(`${baseUrl}/products`, { cache: 'no-store' });
        if (res.ok) {
            products = await res.json();
        }
    } catch (error) {
        console.error("無法取得商品:", error);
    }


    return (
        <section className="mx-auto max-w-7xl px-6 py-12 md:px-10">
            {/* 標題區：可以加一點品牌氣氛 */}
            <div className="mb-10 flex items-end justify-between border-b border-retro-ink/5 pb-6">
                <div>
                    <h2 className="text-retro-ink text-3xl font-black tracking-tighter italic">ARCHIVE</h2>
                    <p className="text-retro-slate text-sm">Selected pieces for your daily archive.</p>
                </div>
                <span className="text-retro-slate/40 text-[10px] tracking-widest uppercase">
                    Scroll to explore
                </span>
            </div>

            {/* 商品網格：間距建議設為 gap-x-8 gap-y-16，讓視覺有呼吸空間 */}
            <div className="grid grid-cols-1 gap-x-8 gap-y-16 sm:grid-cols-2 lg:grid-cols-4">
                {products.map((product) => (
                    <ProductCard
                        key={product.id}
                        id={product.id}
                        name={product.name}
                        price={product.price}
                        image={product.image}
                        category={product.category}
                    />
                ))}
            </div>
        </section>
    );
}